static const int kPinyinTableSize =
    (int)(sizeof(kPinyinTable) / sizeof(kPinyinTable[0]));

// ── 比较函数（二分查找） ─────────────────────────────────────────────

static int compare_entry(const void* key, const void* element) {
    unsigned int cp = *(const unsigned int*)key;
    const PinyinEntry* entry = (const PinyinEntry*)element;
    if (cp < entry->cp) return -1;
    if (cp > entry->cp) return  1;
    return 0;
}

// ── API 实现 ─────────────────────────────────────────────────────────

struct PinyinDict {
    int _unused; // reserved for future use
};

PinyinDict* pinyin_dict_new(void) {
    PinyinDict* dict = (PinyinDict*)calloc(1, sizeof(PinyinDict));
    return dict;
}

void pinyin_dict_free(PinyinDict* dict) {
    free(dict);
}

int pinyin_first_letter(PinyinDict* dict, unsigned int cp,
                         char* buf, int bufsz) {
    (void)dict;
    if (!buf || bufsz < 2) return 0;

    PinyinEntry* found = (PinyinEntry*)bsearch(
        &cp, kPinyinTable, kPinyinTableSize,
        sizeof(PinyinEntry), compare_entry);

    if (!found) return 0;

    int len = (int)strlen(found->letters);
    if (len >= bufsz) len = bufsz - 1;
    memcpy(buf, found->letters, len);
    buf[len] = '\0';
    return len;
}
